 //this is to be used when I allow multiple banks
const snippet = $input.first().json.snippet || '';
const from = ($input.first().json.from || '').toLowerCase();
const date = $input.first().json.internalDate || Date.now();
const txDate = new Date(parseInt(date)).toISOString();

let amount = 0;
let description = 'Bank Transaction';
let recipientBank = '';
let bankName = 'Unknown';

// ── OPAY ────────────────────────────────────────────────
if (from.includes('opay-nigeria.com')) {
  bankName = 'OPay';

  // Amount: "₦500.00"
  const amountMatch = snippet.match(/₦([\d,]+\.?\d*)/);
  if (amountMatch) {
    amount = parseFloat(amountMatch[1].replace(/,/g, ''));
  }

  // Name: handles "Name: JOHN DOE" and "Name: AWE/john doe"
  const nameMatch = snippet.match(/Name:\s*(.+?)\s+Bank:/i);
  if (nameMatch) {
    let rawName = nameMatch[1].trim();
    if (rawName.includes('/')) {
      rawName = rawName.split('/').pop().trim();
    }
    description = rawName.trim();
  }

  // Recipient Bank
  const bankMatch = snippet.match(/Bank:\s*([A-Za-z\s]+?)(?:Account|PLC|$)/i);
  if (bankMatch) {
    recipientBank = bankMatch[1].trim();
  }
}

// ── GTBANK ──────────────────────────────────────────────
else if (from.includes('gtbank.com')) {
  bankName = 'GTBank';

  // Amount: "NGN 2400" or "NGN2400"
  const amountMatch = snippet.match(/Amount\s*:?\s*NGN\s*([\d,]+\.?\d*)/i);
  if (amountMatch) {
    amount = parseFloat(amountMatch[1].replace(/,/g, ''));
  }

  // Description: after "Description :" 
  const descMatch = snippet.match(/Description\s*:(.*?)(?:Amount|Value Date)/is);
  if (descMatch) {
    let rawDesc = descMatch[1].trim();
    // Extract recipient name after "TO"
    const toMatch = rawDesc.match(/(?:NIP TRANSFER TO|TRANSFER TO)\s+([A-Z\s\-]+?)(?:\s*$|-\s*[A-Z])/i);
    if (toMatch) {
      description = toMatch[1].trim();
    } else {
      description = rawDesc.substring(0, 50).trim();
    }
  }

  // Remarks (contains cleaner description)
  const remarksMatch = snippet.match(/Remarks\s*:(.*?)(?:Time|$)/is);
  if (remarksMatch) {
    recipientBank = remarksMatch[1].trim();
  }
}

// ── STERLING BANK ────────────────────────────────────────
else if (from.includes('sterling.ng')) {
  bankName = 'Sterling Bank';

  // Amount: "NGN2,500.00"
  const amountMatch = snippet.match(/Amount\s*NGN([\d,]+\.?\d*)/i);
  if (amountMatch) {
    amount = parseFloat(amountMatch[1].replace(/,/g, ''));
  }

  // Description: "OneBank Transfer from X to Y"
  const descMatch = snippet.match(/Description\s+(.+?)(?:Amount|$)/is);
  if (descMatch) {
    let rawDesc = descMatch[1].trim();
    // Extract recipient (after "to")
    const toMatch = rawDesc.match(/to\s+([A-Z\s]+?)$/i);
    if (toMatch) {
      description = toMatch[1].trim();
    } else {
      description = rawDesc.substring(0, 50).trim();
    }
  }

  recipientBank = 'Sterling Bank';
}

// ── KUDA ────────────────────────────────────────────────
else if (from.includes('kuda.com')) {
  bankName = 'Kuda';

  // Amount + recipient + narration: "You just sent ₦2,100.00 to Marcus Olaitan - Food."
  const kudaMatch = snippet.match(/you just sent\s+₦([\d,]+\.?\d*)\s+to\s+(.+?)(?:\.|$)/i);
  if (kudaMatch) {
    amount = parseFloat(kudaMatch[1].replace(/,/g, ''));

    // Split recipient and narration by " - "
    const parts = kudaMatch[2].split(' - ');
    description = parts[0].trim();

    // 🎉 Kuda includes narration! Use it for better categorization
    if (parts[1]) {
      recipientBank = parts[1].trim(); // we'll use this field for narration
    }
  }
}

return [{
  json: {
    description: description,
    amount: amount,
    date: txDate,
    recipientBank: recipientBank,
    bank: bankName,
    emailBody: snippet.substring(0, 500),
  }
}];

const snippet = ($input.first().json.emailBody || '').toLowerCase();
const description = ($input.first().json.description || '').toLowerCase();
const amount = $input.first().json.amount || 0;

let category = 'Transfer'; // default for person-to-person OPay sends

// FOOD & DINING
const foodKeywords = [
  'chowdeck', 'jumia food', 'bolt food', 'glovo', 'eatrite',
  'restaurant', 'kitchen', 'eatery', 'suya', 'bukka', 'canteen',
  'food', 'pizza', 'chicken', 'burger', 'shawarma', 'cafe', 'bakery',
  'choplife', 'crunchies', 'dominos', 'kfc', 'mcdonalds', 'kilimanjaro'
];

// TRANSPORTATION
const transportKeywords = [
  'uber', 'bolt', 'taxify', 'indriver', 'rida',
  'fuel', 'petrol', 'filling station', 'ardova', 'nipco', 'total',
  'transport', 'bus', 'ride', 'trip', 'fare', 'logistics'
];

// AIRTIME & DATA
const airtimeKeywords = [
  'mtn', 'airtel', 'glo', '9mobile', 'etisalat',
  'airtime', 'data', 'recharge', 'bundle', 'subscription',
  'smile', 'spectranet', 'ipnx'
];

// ENTERTAINMENT
const entertainmentKeywords = [
  'netflix', 'spotify', 'youtube', 'showmax', 'dstv', 'gotv',
  'startimes', 'cinema', 'filmhouse', 'genesis', 'silverbird',
  'event', 'ticket', 'concert', 'game', 'playstation', 'xbox',
  'apple music', 'audiomack', 'boomplay'
];

// EDUCATION
const educationKeywords = [
  'school', 'university', 'college', 'tuition', 'fees',
  'course', 'udemy', 'coursera', 'tutorial', 'training',
  'book', 'stationery', 'exam', 'waec', 'jamb', 'neco',
  'student', 'lecture', 'academy'
];

// SHOPPING
const shoppingKeywords = [
  'jumia', 'konga', 'jiji', 'payporte', 'fashion',
  'mall', 'store', 'shop', 'market', 'cloth', 'shoe',
  'bag', 'electronics', 'phone', 'laptop', 'gadget',
  'supermarket', 'shoprite', 'spar', 'ebeano'
];

// BILLS & UTILITIES
const billsKeywords = [
  'electricity', 'nepa', 'phcn', 'ikedc', 'ekedc', 'aedc',
  'water', 'lawma', 'waste', 'rent', 'landlord',
  'internet', 'wifi', 'cable', 'insurance'
];

// GIFT
const giftKeywords = [
  'gift', 'present', 'birthday', 'anniversary', 'celebration',
  'surprise', 'hamper', 'bouquet', 'appreciation', 'token',
  'goodwill', 'happy birthday', 'well done', 'congratulations'
];

// DEBT REPAYMENT
const debtKeywords = [
  'debt', 'owe', 'owed', 'loan',
  'pay back', 'paying back',
  'borrow', 'borrowed', 'lend',
  'settle', 'settlement',
  'i owe', 'you owe', 'outstanding'
];

// Match against all keyword lists
const narration = ($input.first().json.recipientBank || '').toLowerCase();
const allText = snippet + ' ' + description + ' ' + narration;

if (foodKeywords.some(k => allText.includes(k))) {
  category = 'Food & Dining';
} else if (transportKeywords.some(k => allText.includes(k))) {
  category = 'Transportation';
} else if (airtimeKeywords.some(k => allText.includes(k))) {
  category = 'Airtime & Data';
} else if (entertainmentKeywords.some(k => allText.includes(k))) {
  category = 'Entertainment';
} else if (educationKeywords.some(k => allText.includes(k))) {
  category = 'Education';
} else if (shoppingKeywords.some(k => allText.includes(k))) {
  category = 'Shopping';
} else if (billsKeywords.some(k => allText.includes(k))) {
  category = 'Bills & Utilities';
} else if (giftKeywords.some(k => allText.includes(k))) {
  category = 'Gift';
} else if (debtKeywords.some(k => allText.includes(k))) {
  category = 'Debt Repayment';
}

return [{
  json: {
    description: $input.first().json.description,
    amount: $input.first().json.amount,
    date: $input.first().json.date,
    recipientBank: $input.first().json.recipientBank,
    bank: $input.first().json.bank,
    emailBody: $input.first().json.emailBody,
    category: category
  }
}];
